INSERT INTO public.foundations (id, profile_id, foundation_name, description, logo_url, location_city, location_address, whatsapp_number, email, website_url, is_verified, verified_at, donation_link, instagram_url, facebook_url, created_at, updated_at) VALUES
('cf755913-f31e-45e6-8fa1-9f482a19276f', 'f05703f0-a142-4fb4-b7fa-91580d009245', 'Patitas Felices Pasto', 'Somos una fundación dedicada al rescate, rehabilitación y adopción de perros y gatos en situación de calle en Pasto. Desde 2018 hemos encontrado hogar para más de 500 peluditos. Trabajamos con amor y dedicación para darles una segunda oportunidad.', NULL, 'Pasto', 'Barrio Lorenzo, Calle 18 #25-30', '573101234567', 'patitasfelices@email.com', NULL, true, '2025-11-30 01:32:17.00029+00', 'https://nequi.com/patitasfelices', 'https://instagram.com/patitasfelicespasto', 'https://facebook.com/patitasfelicespasto', '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('552a637d-f3d3-4c84-9c14-7f643164b7ea', '1d475296-8a2d-44fe-ae63-34b18e084686', 'Gatos de Pasto', 'Nos especializamos en el rescate y cuidado de gatos abandonados en Pasto. Brindamos atención veterinaria, esterilización y encontramos hogares responsables. Cada gato merece amor y un hogar cálido.', NULL, 'Pasto', 'Centro, Carrera 27 #16-45', '573201234567', 'gatosdepasto@email.com', NULL, true, '2025-11-30 01:32:17.00029+00', 'https://daviplata.com/gatosdepasto', 'https://instagram.com/gatosdepasto', NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00'),
('b3a0b67f-caf8-40b3-a439-8cb94350e80d', 'beabee59-de23-43ef-b3b4-5865ba5e4d68', 'Rescate Animal Nariño', 'Rescatamos y rehabilitamos animales víctimas de maltrato y abandono en todo el departamento de Nariño. Nuestro refugio temporal les brinda un espacio seguro mientras encuentran su familia definitiva.', NULL, 'Pasto', 'Aranda, Calle 12 #8-15', '573151234567', 'rescateanimalnarino@email.com', NULL, true, '2025-11-30 01:32:17.00029+00', 'https://nequi.com/rescateanimalnarino', NULL, NULL, '2025-11-30 01:32:17.00029+00', '2025-11-30 01:32:17.00029+00');
